"use client";

import { useRef, useEffect } from "react";
import { SectionWrapper } from "@/components/ui/SectionWrapper";
import { motion, useInView, useMotionValue, useSpring } from "framer-motion";
import { cn } from "@/lib/utils";

const stats = [
  { 
    value: 8, 
    suffix: "+", 
    label: "Systems Deployed",
    description: "Operational across web & mobile sectors"
  },
  { 
    value: 2, 
    suffix: "+", 
    label: "Light Years", 
    description: "Journey in tech & operations"
  },
  { 
    value: 6, 
    suffix: "+", 
    label: "Core Modules", 
    description: "Mastery of modern frameworks"
  },
  { 
    value: 100, 
    suffix: "%", 
    label: "Mission Success", 
    description: "Dedicated to project completion"
  },
];

function Counter({ value, suffix, className }: { value: number, suffix: string, className?: string }) {
  const ref = useRef<HTMLSpanElement>(null);
  const motionValue = useMotionValue(0);
  const springValue = useSpring(motionValue, {
    damping: 50,
    stiffness: 100,
    duration: 2
  });
  const isInView = useInView(ref, { once: true, margin: "-100px" });

  useEffect(() => {
    if (isInView) {
      motionValue.set(value);
    }
  }, [isInView, value, motionValue]);

  useEffect(() => {
    return springValue.on("change", (latest) => {
      if (ref.current) {
        ref.current.textContent = latest.toFixed(0) + suffix;
      }
    });
  }, [springValue, suffix]);

  return <span ref={ref} className={className} />;
}

export function Stats() {
  return (
    <SectionWrapper className="relative overflow-hidden py-32">
      {/* Background Grid Effect */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:4rem_4rem] [mask-image:radial-gradient(ellipse_60%_60%_at_50%_50%,black,transparent)] pointer-events-none" />
      
      {/* HUD Lines */}
      <div className="absolute top-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-white/20 to-transparent" />
      <div className="absolute bottom-0 left-0 w-full h-px bg-gradient-to-r from-transparent via-white/20 to-transparent" />

      <div className="flex flex-col items-center mb-20 relative z-10">
         <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="flex items-center gap-2 mb-4"
         >
            <span className="w-12 h-[1px] bg-accent" />
            <span className="text-accent font-mono text-sm tracking-[0.2em] uppercase">Telemetry</span>
            <span className="w-12 h-[1px] bg-accent" />
         </motion.div>
         
         <motion.h2 
            initial={{ opacity: 0, scale: 0.9 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            className="text-5xl md:text-7xl font-heading font-bold uppercase text-center bg-clip-text text-transparent bg-gradient-to-b from-white to-white/40"
         >
            Mission <span className="text-accent">Stats</span>
         </motion.h2>
      </div>
      
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 relative z-10">
        {stats.map((stat, index) => (
          <motion.div
            key={index}
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: index * 0.1 }}
            className="group relative"
          >
            {/* HUD Card Design */}
            <div className="relative bg-[#050505]/50 backdrop-blur-sm border border-white/10 p-8 flex flex-col items-center justify-center text-center overflow-hidden hover:border-accent/50 transition-colors duration-500">
                {/* Corner Markers */}
                <div className="absolute top-0 left-0 w-3 h-3 border-l border-t border-white/30 group-hover:border-accent transition-colors" />
                <div className="absolute top-0 right-0 w-3 h-3 border-r border-t border-white/30 group-hover:border-accent transition-colors" />
                <div className="absolute bottom-0 left-0 w-3 h-3 border-l border-b border-white/30 group-hover:border-accent transition-colors" />
                <div className="absolute bottom-0 right-0 w-3 h-3 border-r border-b border-white/30 group-hover:border-accent transition-colors" />

                <div className="mb-4 relative">
                   <Counter value={stat.value} suffix={stat.suffix} className="text-6xl md:text-7xl font-heading font-bold text-white group-hover:text-accent transition-colors duration-500" />
                   <div className="absolute -inset-4 bg-accent/20 blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-full" />
                </div>
                
                <h3 className="text-sm font-mono uppercase tracking-widest text-white/80 mb-2">{stat.label}</h3>
                <p className="text-xs text-white/40 font-mono">{stat.description}</p>
            </div>
          </motion.div>
        ))}
      </div>
    </SectionWrapper>
  );
}
