export const AlienPeeking = ({ className = "" }: { className?: string }) => {
    return (
        <motion.div
            className={`absolute z-10 ${className}`}
            initial={{ y: 100 }}
            whileInView={{ y: 0 }}
            viewport={{ once: false, margin: "0px 0px -100px 0px" }}
            transition={{ type: "spring", stiffness: 100, damping: 20 }}
        >
            <div className="relative w-24 h-24">
                {/* Head */}
                <div className="w-20 h-16 bg-green-400 rounded-[40%_40%_50%_50%] absolute bottom-0 left-1/2 -translate-x-1/2 border-2 border-green-600 shadow-lg">
                    {/* Eyes */}
                    <motion.div 
                        className="absolute top-4 left-3 w-5 h-7 bg-black rounded-[50%_50%_40%_40%] rotate-[-15deg]"
                        animate={{ scaleY: [1, 0.1, 1] }}
                        transition={{ duration: 0.2, repeat: Infinity, repeatDelay: 3 }}
                    >
                        <div className="absolute top-1 left-1 w-1.5 h-1.5 bg-white rounded-full opacity-80" />
                    </motion.div>
                    <motion.div 
                        className="absolute top-4 right-3 w-5 h-7 bg-black rounded-[50%_50%_40%_40%] rotate-[15deg]"
                        animate={{ scaleY: [1, 0.1, 1] }}
                        transition={{ duration: 0.2, repeat: Infinity, repeatDelay: 3.5 }}
                    >
                        <div className="absolute top-1 right-1 w-1.5 h-1.5 bg-white rounded-full opacity-80" />
                    </motion.div>
                    {/* Mouth */}
                    <div className="absolute bottom-3 left-1/2 -translate-x-1/2 w-4 h-1 bg-green-700 rounded-full opacity-50" />
                </div>
                {/* Hands */}
                <div className="absolute bottom-0 left-0 w-6 h-6 bg-green-400 rounded-full border-2 border-green-600" />
                <div className="absolute bottom-0 right-0 w-6 h-6 bg-green-400 rounded-full border-2 border-green-600" />
            </div>
        </motion.div>
    )
}

export const FloatingSticker = ({ 
    children, 
    className = "", 
    delay = 0, 
    rotate = 12 
}: { 
    children: React.ReactNode, 
    className?: string, 
    delay?: number,
    rotate?: number 
}) => {
    return (
        <motion.div
            className={`absolute z-10 select-none pointer-events-none ${className}`}
            initial={{ opacity: 0, scale: 0.8, rotate: rotate - 10 }}
            whileInView={{ opacity: 1, scale: 1, rotate: rotate }}
            transition={{ duration: 0.5, delay }}
            viewport={{ once: true }}
        >
            <motion.div
                animate={{ y: [0, -10, 0] }}
                transition={{ duration: 3, repeat: Infinity, ease: "easeInOut", delay: Math.random() * 2 }}
                className="relative group"
            >
                {/* Sticker Border/Background */}
                <div className="absolute -inset-1 bg-white rounded-xl skew-y-1 shadow-lg" />
                {/* Content */}
                <div className="relative bg-gradient-to-br from-slate-100 to-slate-200 px-3 py-2 rounded-lg border border-slate-300 flex items-center justify-center font-bold text-slate-800 text-sm md:text-base uppercase tracking-wider shadow-inner">
                    {children}
                </div>
                {/* Shine effect */}
                <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/40 to-transparent rounded-lg pointer-events-none" />
            </motion.div>
        </motion.div>
    );
}

